// Create Summary - Aggregate all articles
const allItems = $input.all();

console.log('📦 Total items received:', allItems.length);

// Group by source
const bySource = {};

allItems.forEach(item => {
  const article = item.json.original_article || item.json;
  const source = article.crawler_source || 'unknown';

  if (!bySource[source]) {
    bySource[source] = {
      source_id: source,
      source_name: article.crawler_source_name || article.source || source,
      total: 0,
      successful: 0,
      failed: 0
    };
  }

  bySource[source].total++;

  if (item.json.error) {
    bySource[source].failed++;
  } else {
    bySource[source].successful++;
  }
});

const summary = {
  run_id: allItems[0]?.json.run_id || allItems[0]?.json.original_article?.run_id || Date.now(),
  completed_at: new Date().toISOString(),
  total_sources: Object.keys(bySource).length,
  total_articles: allItems.length,
  successful: allItems.filter(i => !i.json.error).length,
  failed: allItems.filter(i => i.json.error).length,
  by_source: Object.values(bySource)
};

console.log('📊 Final Summary:', JSON.stringify(summary, null, 2));

return [{ json: summary }];

// Prepare Summary Log - GET FROM CREATE SUMMARY
const summary = $('Create Summary1').first().json;

console.log('📊 Summary:', JSON.stringify(summary, null, 2));

let logCommand = 'echo "[$(date -Iseconds)] ========== RUN ' + summary.run_id + ' COMPLETED ==========" >> /tmp/crawler/logs/master.log && ';
logCommand += 'echo "[$(date -Iseconds)] Total Sources: ' + summary.total_sources + ', Total Articles: ' + summary.total_articles + ', Success: ' + summary.successful + ', Failed: ' + summary.failed + '" >> /tmp/crawler/logs/master.log';

// Per-source breakdown
if (summary.by_source && summary.by_source.length > 0) {
  summary.by_source.forEach(src => {
    logCommand += ' && echo "[$(date -Iseconds)] [' + src.source_id + '] Total: ' + src.total + ', Success: ' + src.successful + ', Failed: ' + src.failed + '" >> /tmp/crawler/logs/master.log';
  });
}

return [{
  json: {
    ...summary,
    log_command: logCommand
  }
}];

// Prepare Article Log - WITH INPUT DATA
const response = $json;

// Original article data inputData'da olacak
const article = $input.item.json || $json;

console.log('📦 Article keys:', Object.keys(article));
console.log('📦 Source:', article.crawler_source);
console.log('📦 ID:', article.id);

const source = article.crawler_source || 'unknown';
const articleId = (article.id || 'no-id').substring(0, 80);
const safeId = articleId.replace(/"/g, '\\"');

const logCommand = 'echo "[$(date -Iseconds)] [' + source + '] Article saved - ID: ' + safeId + '" >> /tmp/crawler/logs/' + source + '.log';

return [{
  json: {
    ...response,
    original_article: article,
    log_command: logCommand
  }
}];

// Parse Articles - RUN ONCE FOR EACH ITEM
const articles = $json.data;

// Error handling
if (!articles) {
  console.log('⚠️ Empty response from crawler');
  throw new Error('Empty response from crawler');
}

let parsedArticles;
if (typeof articles === 'string') {
  if (articles.trim() === '' || articles === '[]') {
    throw new Error('Empty response from crawler');
  }
  try {
    parsedArticles = JSON.parse(articles);
  } catch (e) {
    console.log('❌ JSON parse error:', e.message);
    throw new Error('JSON parse failed: ' + e.message);
  }
} else {
  parsedArticles = articles;
}

if (!Array.isArray(parsedArticles) || parsedArticles.length === 0) {
  console.log('⚠️ No articles found');
  throw new Error('No articles found for this source');
}

// Source bilgisini al
const allSourceInputs = $('Define All Sources').all();
const sourceInfo = allSourceInputs[$itemIndex].json;

console.log('🔍 Processing Source #' + $itemIndex + ':', sourceInfo.id, '- Articles:', parsedArticles.length);

const runId = sourceInfo.run_id || Date.now();
const retrievedAt = new Date().toISOString();

function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return Math.abs(hash).toString(36);
}

// ✅ ARRAY'İ BİR OBJECT İÇİNE KOYARAK DÖNDÜR
const processedArticles = parsedArticles.map((article, articleIndex) => {
  const originalUrl = article.url || article.link || article.id;

  let uniqueString;
  if (originalUrl && (originalUrl.startsWith('http://') || originalUrl.startsWith('https://'))) {
    uniqueString = originalUrl.toLowerCase().trim();
  } else {
    const title = (article.title || '').toLowerCase().trim();
    const date = article.published_date || article.date || '';
    uniqueString = `${sourceInfo.id}-${title}-${date}`;
  }

  const hash = simpleHash(uniqueString);
  const cleanId = `${sourceInfo.id}-${hash}`;

  return {
    ...article,
    _opensearch_id: cleanId,
    url: originalUrl,
    id: originalUrl,
    crawler_source: sourceInfo.id,
    crawler_source_name: sourceInfo.name,
    run_id: runId,
    article_index: articleIndex,
    total_for_this_source: parsedArticles.length,
    retrieved_at: retrievedAt
  };
});

// ✅ TEK OBJE DÖNDÜR (Run Once for Each Item kuralı)
return {
  json: {
    source: sourceInfo.id,
    articles: processedArticles  // Array içeride
  }
};

// Define all news sources (only functional endpoints)
const sources = [
  { name: 'CNN', id: 'cnn', endpoint: 'cnn' },
  { name: 'ESPN', id: 'espn', endpoint: 'espn' },
  { name: 'Fox News', id: 'foxnews', endpoint: 'foxnews' },
  { name: 'Goal', id: 'goal', endpoint: 'goal' },
  { name: 'Guardian', id: 'guardian', endpoint: 'guardian' },
  { name: 'Guardian Sport', id: 'guardiansport', endpoint: 'guardiansport' },
  { name: 'Japan Times', id: 'japantimes', endpoint: 'japantimes' },
  { name: 'NBC', id: 'nbc', endpoint: 'nbc' },
  { name: 'SBS', id: 'sbs', endpoint: 'sbs' },
  { name: 'SCMP Economics', id: 'scmp_economics', endpoint: 'southchinamorningpost/economics' },
  { name: 'SCMP Politics', id: 'scmp_politics', endpoint: 'southchinamorningpost/politics' },
  { name: 'Tass', id: 'tass', endpoint: 'tass' },
  { name: 'TeleSur', id: 'telesur', endpoint: 'telesur' },
  { name: 'The News', id: 'thenews', endpoint: 'thenews' },
  { name: 'Times of India', id: 'timesofindia', endpoint: 'timesofindia' },
  { name: 'Yahoo Finance', id: 'yahoofinance', endpoint: 'yahoofinance' },
  { name: 'Yahoo News', id: 'yahoonews', endpoint: 'yahoonews' },
  { name: 'RSS Feeds', id: 'rss', endpoint: 'rss' }
];

const runId = Date.now();
return sources.map(source => ({
  json: {
    ...source,
    run_id: runId,
    started_at: new Date().toISOString()
  },
  pairedItem: { item: 0 }
}));

// Split Articles - RUN ONCE FOR ALL ITEMS
const allItems = $input.all();

console.log('📦 Total sources processed:', allItems.length);

const result = [];

allItems.forEach((item, sourceIndex) => {
  console.log('Processing source', sourceIndex, ':', item.json.source);

  const articles = item.json.articles;

  if (!articles) {
    console.log('⚠️ No articles field found in item', sourceIndex);
    return;
  }

  if (!Array.isArray(articles)) {
    console.log('⚠️ Articles is not an array in item', sourceIndex);
    return;
  }

  console.log('  → Found', articles.length, 'articles');

  articles.forEach((article, idx) => {
    // ✅ TABLOYA UYGUN FIELD MAPPING
    result.push({ 
      json: {
        id: article._opensearch_id,                          // Keyword - unique ID
        url: article.url,
        title: article.title || '',                          // Text
        body: article.body || article.description || '',     // Text
        language: article.language || 'en',                  // Keyword - ISO code
        source: article.crawler_source,                      // Keyword - Publisher
        published_at: article.published_date || article.date || article.retrieved_at, // Date - ISO-8601

        // Extra metadata (opsiyonel)
        _metadata: {
          crawler_source_name: article.crawler_source_name,
          article_index: article.article_index,
          total_for_this_source: article.total_for_this_source,
          run_id: article.run_id,
          original_url: article.url
        }
      }
    });
  });
});

console.log('✅ Total articles to index:', result.length);

return result;
